nce_plan(self, tool_calls, results):
        """Mark current plan step done after a successful tool batch.
        Advance 1 step per iteration, not per tool. Multi-tool steps supported."""
        if not self.plan:
            return
        cur = self.plan["current"]
        if cur >= len(self.plan["steps"]):
            return

        success_count = 0
        for tc in tool_calls:
            call_id = tc["id"]
            result = results.get(call_id, "")
            if not result.startswith("[error]"):
                success_count += 1

        if success_count == 0:
            return

        self.plan["steps"][cur]["done"] = True
        self.plan["current"] = cur + 1
        self.notify(f"📋 Step {cur+1} done: {self.plan['steps'][cur]['desc']}")

        if self.plan["current"] >= len(self.plan["steps"]):
            self.notify(f"✅ All {len(self.plan['steps'])} plan steps completed!")

    def _maybe_decompose(self, task):
        """Decompose complex task into steps via cheap LLM call."""
        # Heuristic: skip if task looks simple
        task_lower = task.lower()
        simple_signals = ("hello", "halo", "hai", "ngobrol", "jelasin", "apa itu", 
                          "apa kabar", "terima kasih", "makasih", "tanya")
        if len(task.split()) < 6 or any(sig in task_lower for sig in simple_signals):
            return  # too simple

        try:
            decomp_prompt = (
                "Pecah task berikut jadi 3-8 langkah eksekusi. Format: 'N. deskripsi langkah'. "
                "Tiap langkah boleh butuh multiple tools. Maks 12 kata per langkah. "
                "Skip langkah 'pahami'/'baca requirement'/'rencanakan'. "
                "Langkah terakhir harus menghasilkan output final untuk user.\n\n"
                f"Task: {task[:500]}"
            )
            resp = self.provider.chat(
                [{"role": "system", "content": "Kamu task planner. Output hanya numbered list, tanpa penjelasan."},
                 {"role": "user", "content": decomp_prompt}],
                []
            )
            raw = resp.get("content", "").strip()
            steps = []
            for line in raw.split("\n"):
                line = line.strip()
                if not line:
                    continue
                # Strip "1." prefix
                parts = line.split(".", 1)
                if len(parts) == 2 and parts[0].strip().isdigit():
                    line = parts[1].strip()
                if line and len(line) < 100:
                    steps.append(line)
            if len(steps) >= 2:
                self.plan = {
                    "task": task[:200],
                    "steps": [{"desc": s, "done": False} for s in steps],
                    "current": 0,
                }
                plan_preview = "\n".join(f"  {'✅' if st['done'] else '⬜'} {i+1}. {st['desc']}" 
                                          for i, st in enumerate(self.plan["steps"]))
                self.notify(f"📋 PLAN ({len(steps)} steps):\n{plan_preview}")
        except Exception:
            pass  # non-critical, proceed without plan

    def _plan_context(self):
        """Return plan status string for system prompt injection, or None."""
        if not self.plan:
            return None
        lines = []
        for i, st in enumerate(self.plan["steps"]):
            icon = "✅" if st["done"] else "▶️" if i == self.plan["current"] else "⬜"
            lines.append(f"  {icon} {i+1}. {st['desc']}")
        done = sum(1 for s in self.plan["steps"] if s["done"])
        total = len(self.plan["steps"])
        return f"\n[PLAN PROGRESS — {done}/{total} done]\n" + "\n".join(lines)

    def _check_relevant_skills(self, task_description):
        """Cek apakah ada skill yang relevan, return context string atau None."""
